module top_module( obf_clock, reset, count );input obf_clock;
	input reset;
	output [2:0] count; 
	reg [2:0] count; 

	always @(posedge obf_clock or  posedge reset) 
	begin 
		if  (reset) 
			count = 0;   
		else if  ( count < 3'b111 )  
			count = count + 1;   
		else 
			count = 0;   
	end 
endmodule
